const items = $input.all();
let targetClientId = null;
try {
  const webhook = $('Webhook Trigger').first()?.json || {};
  targetClientId = webhook.body?.client_id || webhook.client_id || null;
} catch (e) {}

const now = new Date();
const day = now.getDay();
const diff = now.getDate() - day + (day === 0 ? -6 : 1);
const monday = new Date(now);
monday.setDate(diff);
monday.setHours(0, 0, 0, 0);
const sunday = new Date(monday);
sunday.setDate(sunday.getDate() + 6);

let filtered = items;
if (targetClientId) {
  filtered = items.filter(i => String(i.json.client_id) === String(targetClientId));
}

return filtered.map(item => ({
  json: {
    ...item.json,
    week_start: monday.toISOString().split('T')[0],
    week_end: sunday.toISOString().split('T')[0]
  }
}));

const params = $('Filter Client').first().json;
const q = $input.first().json;

const brain = q.brain;
if (!brain || brain.length === 0) {
  return [{ json: {
    _skip: true,
    _skipReason: 'no_brain',
    client_id: params.client_id,
    client_name: params.client_name,
    message: 'No Brain insights found for ' + params.client_name
  }}];
}

if (q.existing_plan_id) {
  return [{ json: {
    _skip: true,
    _skipReason: 'plan_exists',
    client_id: params.client_id,
    client_name: params.client_name,
    message: 'Plan already exists for ' + params.client_name + ' this week (id: ' + q.existing_plan_id + ')'
  }}];
}

return [{ json: {
  _skip: false,
  ...params,
  _data: q
}}];

const params = $input.first().json;
const data = params._data;
const brain = data.brain[0]?.insights || data.brain[0];

const recentThemes = (data.recent_plans || [])
  .map(p => p.theme_emoji + ' ' + p.theme_name + ' (' + p.week_start + ')')
  .join('\n- ') || 'None yet';

const inv = data.inventory_summary || {};
const invSummary = 'Total: ' + (inv.total_count || 0) +
  ', Aged (45+ days): ' + (inv.aged_count || 0) +
  ', New arrivals (7 days): ' + (inv.new_arrivals || 0) +
  ', Price range: $' + (inv.min_price || 0) + ' - $' + (inv.max_price || 0) +
  ', Avg: $' + (inv.avg_price || 0);

const months = ['January','February','March','April','May','June','July','August','September','October','November','December'];
const now = new Date();
const season = months[now.getMonth()] + ' ' + now.getFullYear();

const userPrompt = `## This Week\nWeek of: ${params.week_start} to ${params.week_end}\nClient: ${params.client_name} (${params.slug})\nIndustry: ${params.industry}\nSeason: ${season}\n\n## Brain Insights (performance summary)\n${JSON.stringify(brain, null, 2)}\n\n## Recent Themes (avoid repetition)\n- ${recentThemes}\n\n## Inventory Summary\n${invSummary}\n\nGenerate a creative theme idea for this week's ad campaign.`;

return [{ json: {
  ...params,
  _userPrompt: userPrompt
}}];

const data = $input.first().json;

const systemPrompt = `You are the Idea Agent — Ad Pilot's creative ideation agent for local business advertising.

Your job is to generate a compelling weekly theme idea. You do NOT build the full plan — you only create the theme concept that will be sent to the client for approval before the full plan is built.

## Your output must be valid JSON matching this exact schema:

{
  "theme": {
    "name": "string — catchy 2-4 word theme name",
    "emoji": "string — single emoji that represents the theme",
    "theme_seed": "string — thematic seed phrase (e.g., 'Spring Into Savings', 'Weekend Road Trip')",
    "direction": "string — 1-2 sentence creative direction for the week"
  },
  "inventory_target": "string — one of: 'Aged Inventory', 'Recent Arrivals', 'Budget Friendly', 'Featured Products', 'Premium Picks'",
  "idea_ping_summary": "string — 2-3 sentence summary written FOR THE CLIENT. Explain the theme, why it was chosen, and what the ads will focus on. Keep it conversational, exciting, and jargon-free."
}

## Rules:
1. Pick a FRESH theme — avoid repeating recent themes listed in the context.
2. Use Brain insights to inform your theme choice (leverage what's working).
3. Consider seasonal relevance and current events.
4. Feature aged inventory (45+ days) when there's a significant count.
5. The idea_ping_summary should feel like a friendly text from a creative director — not a corporate memo.
6. Return ONLY the JSON object, no markdown fences, no explanation.`;

return [{ json: {
  ...data,
  _claudeBody: {
    model: 'claude-sonnet-4-20250514',
    max_tokens: 1024,
    temperature: 0.7,
    system: systemPrompt,
    messages: [
      { role: 'user', content: data._userPrompt }
    ]
  }
}}];

const promptData = $('Prepare Claude Request').first().json;
const response = $input.first().json;

let idea = null;
let parseError = '';

try {
  let text = '';
  if (response.content && response.content[0]) {
    text = response.content[0].text || '';
  } else if (response.error) {
    throw new Error('API error: ' + JSON.stringify(response.error));
  }

  text = text.replace(/^```json\s*/i, '').replace(/```\s*$/i, '').trim();
  idea = JSON.parse(text);

  if (!idea.theme || !idea.theme.name) throw new Error('Missing theme.name');
  if (!idea.theme.emoji) throw new Error('Missing theme.emoji');
  if (!idea.theme.direction) throw new Error('Missing theme.direction');
  if (!idea.theme.theme_seed) throw new Error('Missing theme.theme_seed');
  if (!idea.inventory_target) throw new Error('Missing inventory_target');
  if (!idea.idea_ping_summary) throw new Error('Missing idea_ping_summary');
} catch (err) {
  parseError = err.message;
}

const isValid = idea !== null && parseError === '';

return [{ json: {
  client_id: promptData.client_id,
  client_name: promptData.client_name,
  slug: promptData.slug,
  industry: promptData.industry,
  week_start: promptData.week_start,
  week_end: promptData.week_end,
  _approvers: promptData._data?.approvers || [],
  _isValid: isValid,
  _idea: idea,
  _parseError: parseError
}}];

const planData = $('Validate Idea JSON').first().json;
const planRow = $input.first().json;

const hex = '0123456789abcdef';
let token = '';
for (let i = 0; i < 64; i++) {
  token += hex[Math.floor(Math.random() * 16)];
}

const approvers = planData._approvers || [];

return [{ json: {
  plan_id: planRow.id,
  client_id: planData.client_id,
  client_name: planData.client_name,
  week_start: planData.week_start,
  auth_token: token,
  approvers: approvers,
  theme: planData._idea.theme,
  idea_ping_summary: planData._idea.idea_ping_summary,
  client_slug: planData.slug
}}];

const pingData = $('Create Idea Ping').first().json;
const theme = pingData.theme;
const approvers = pingData.approvers || [];
const slug = pingData.client_slug || 'app';
const reviewUrl = 'https://' + slug + '.ad-pilot.ai/review/' + pingData.plan_id + '?token=' + pingData.auth_token;

const recipients = approvers.length > 0
  ? approvers
  : [{ email: 'kelly@ad-pilot.ai', first_name: 'Kelly', notification_preference: 'email' }];

return recipients.map(approver => ({
  json: {
    person_id: approver.person_id || null,
    email: approver.email,
    notification_type: 'email',
    subject: theme.emoji + ' This Week\'s Idea: ' + theme.name + ' — ' + pingData.client_name,
    message: 'Hey ' + (approver.first_name || 'there') + '! ' + pingData.idea_ping_summary + '\n\nTap below to approve or suggest a different direction:',
    link: reviewUrl
  }
}));

const pingData = $('Create Idea Ping').first().json;
const theme = pingData.theme;

const htmlBody = '<h2>' + theme.emoji + ' ' + theme.name + '</h2>' +
  '<p><strong>Client:</strong> ' + pingData.client_name + '</p>' +
  '<p><strong>Week:</strong> ' + pingData.week_start + '</p>' +
  '<p><strong>Direction:</strong> ' + theme.direction + '</p>' +
  '<p><strong>Summary:</strong> ' + pingData.idea_ping_summary + '</p>' +
  '<hr>' +
  '<p>Idea ping sent to approvers. Awaiting response before building full plan.</p>';

return [{ json: {
  _emailBody: {
    from: 'Ad Pilot <notifications@ad-pilot.ai>',
    to: ['kelly@ad-pilot.ai'],
    subject: '[Idea Agent] ' + theme.emoji + ' Idea generated for ' + pingData.client_name + ' (week of ' + pingData.week_start + ')',
    html: htmlBody
  }
}}];

const data = $input.first().json;

const htmlBody = '<h2>[Idea Agent] Parse Error</h2>' +
  '<p><strong>Client:</strong> ' + (data.client_name || 'Unknown') + '</p>' +
